  1	import React, { FC, useEffect, useState } from 'react';
  2	import produce from 'immer';
  3	
  4	import { V1Template } from '@kubevirt-ui/kubevirt-api/console';
  5	import { V1CPU } from '@kubevirt-ui/kubevirt-api/kubevirt';
  6	import CPUInput from '@kubevirt-utils/components/CPUMemoryModal/components/CPUInput/CPUInput';
  7	import MemoryInput from '@kubevirt-utils/components/CPUMemoryModal/components/MemoryInput/MemoryInput';
  8	import { getMemorySize } from '@kubevirt-utils/components/CPUMemoryModal/utils/CpuMemoryUtils';
  9	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 10	import { getTemplateVirtualMachineObject } from '@kubevirt-utils/resources/template';
 11	import { getCPU, getMemory } from '@kubevirt-utils/resources/vm';
 12	import { ensurePath } from '@kubevirt-utils/utils/utils';
 13	import { Alert, Button, ButtonVariant, Modal, ModalVariant } from '@patternfly/react-core';
 14	
 15	import useEditTemplateAccessReview from '../../../../hooks/useIsTemplateEditable';
 16	
 17	import { getDefaultCPUMemoryValues } from './utils';
 18	
 19	import '@kubevirt-utils/components/CPUMemoryModal/cpu-memory-modal.scss';
 20	
 21	type CPUMemoryModalProps = {
 22	  isOpen: boolean;
 23	  onClose: () => void;
 24	  onSubmit: (updatedVMTemplate: V1Template) => Promise<V1Template | void>;
 25	  template: V1Template;
 26	};
 27	
 28	const CPUMemoryModal: FC<CPUMemoryModalProps> = ({ isOpen, onClose, onSubmit, template }) => {
 29	  const { t } = useKubevirtTranslation();
 30	  const vm = getTemplateVirtualMachineObject(template);
 31	
 32	  const { isTemplateEditable } = useEditTemplateAccessReview(template);
 33	
 34	  const [cpu, setCPU] = useState<V1CPU>(getCPU(vm));
 35	  const [memory, setMemory] = useState<number>();
 36	  const [memoryUnit, setMemoryUnit] = useState<string>();
 37	
 38	  const [updateInProcess, setUpdateInProcess] = useState<boolean>(false);
 39	  const [updateError, setUpdateError] = useState<string>();
 40	
 41	  const handleSubmit = async () => {
 42	    setUpdateInProcess(true);
 43	    setUpdateError(null);
 44	
 45	    const updatedTemplate = produce<V1Template>(template, (templateDraft: V1Template) => {
 46	      const draftVM = getTemplateVirtualMachineObject(templateDraft);
 47	
 48	      ensurePath(draftVM, [
 49	        'spec.template.spec.domain.cpu',
 50	        'spec.template.spec.domain.memory.guest',
 51	      ]);
 52	
 53	      draftVM.spec.template.spec.domain.cpu = cpu;
 54	      draftVM.spec.template.spec.domain.memory.guest = `${memory}${memoryUnit}`;
 55	    });
 56	
 57	    try {
 58	      await onSubmit(updatedTemplate);
 59	
 60	      setUpdateInProcess(false);
 61	      onClose();
 62	    } catch (error) {
 63	      setUpdateInProcess(false);
 64	      setUpdateError(error.message);
 65	    }
 66	  };
 67	
 68	  const { defaultCPU, defaultMemory } = getDefaultCPUMemoryValues(template);
 69	  const { defaultMemorySize, defaultMemoryUnit } = defaultMemory;
 70	
 71	  useEffect(() => {
 72	    if (vm?.metadata) {
 73	      const { size: memSize, unit: memUnit } = getMemorySize(getMemory(vm));
 74	      setMemoryUnit(memUnit);
 75	      setMemory(memSize);
 76	      setCPU(getCPU(vm));
 77	    }
 78	  }, [vm]);
 79	
 80	  return (
 81	    <Modal
 82	      actions={[
 83	        <Button
 84	          isDisabled={updateInProcess}
 85	          isLoading={updateInProcess}
 86	          key="confirm"
 87	          onClick={handleSubmit}
 88	          variant={ButtonVariant.primary}
 89	        >
 90	          {t('Save')}
 91	        </Button>,
 92	        <Button
 93	          onClick={() => {
 94	            setCPU(defaultCPU);
 95	            setMemory(defaultMemorySize);
 96	            setMemoryUnit(defaultMemoryUnit);
 97	          }}
 98	          isDisabled={isTemplateEditable}
 99	          key="default"
100	          variant={ButtonVariant.secondary}
101	        >
102	          {t('Restore template settings')}
103	        </Button>,
104	        <Button key="cancel" onClick={onClose} variant="link">
105	          {t('Cancel')}
106	        </Button>,
107	      ]}
108	      className="cpu-memory-modal"
109	      isOpen={isOpen}
110	      onClose={onClose}
111	      title={t('Edit CPU | Memory')}
112	      variant={ModalVariant.small}
113	      width="650px"
114	    >
115	      <div className="inputs">
116	        <CPUInput currentCPU={defaultCPU} setUserEnteredCPU={setCPU} userEnteredCPU={cpu} />
117	        <MemoryInput
118	          memory={memory}
119	          memoryUnit={memoryUnit}
120	          setMemory={setMemory}
121	          setMemoryUnit={setMemoryUnit}
122	        />
123	      </div>
124	      {updateError && (
125	        <Alert isInline title={t('Error')} variant="danger">
126	          {updateError}
127	        </Alert>
128	      )}
129	    </Modal>
130	  );
131	};
132	
133	export default CPUMemoryModal;

